pub struct LogInfoView { pub log_area_len: u64, pub head: u128, pub head_log_area_offset: u64, pub log_length: u64, pub log_plus_pending_length: u64 }

impl View for LogInfo {
    type V = LogInfoView;
    closed spec fn view(&self) -> LogInfoView {
        LogInfoView { log_area_len: self.log_area_len, head: self.head, head_log_area_offset: self.head_log_area_offset, log_length: self.log_length, log_plus_pending_length: self.log_plus_pending_length }
    }
}
